#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef pair<pair<int,int> ,int> pii;
typedef long long ll;
//#define int ll
struct H
{
	priority_queue<pii> h,b;inline bool empty(){return h.size()==b.size();}
	inline void push(pii x){h.push(x);}inline void del(pii x){b.push(x);}
	inline pii top(){while(!b.empty()&&h.top()==b.top())h.pop(),b.pop();return h.top();}
}h;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,M=210;
int a[N],idx[N],d[N],w[N],k,m,b[N],n,nxt[N];
vector<int> in[N],ou[N];ll dp[M][N];
int main()
{
	n=read();k=read();m=read();
	rep(1,m,i)
	{
		int l=read(),r=read();d[i]=read();w[i]=read();
		in[l].push_back(i);ou[r].push_back(i);
	}
	rep(1,n,i)
	{
		for(int v:in[i])h.push({{w[v],d[v]},v});
		if(!h.empty())b[i]=h.top().second;
		for(int v:ou[i])h.del({{w[v],d[v]},v});
	}
	memset(dp,0x3f,sizeof(dp));nxt[n+1]=n+1;
	drep(n,1,i)nxt[i]=(b[i]!=b[i+1]?i+1:nxt[i+1]);
//	printf("%lld\n",dp[0][0]);
//	printf("b   :: ");rep(1,n,i)printf("%d ",b[i]);puts("");
//	printf("nxt :: ");rep(1,n,i)printf("%d ",nxt[i]);puts("");
	rep(0,k,i)
	{
		dp[i][n+1]=0;drep(n,1,j)
		{
//			if(i>=n-j+1){dp[i][j]=0;continue;}
			if(b[j])
			{
				dp[i][j]=dp[i][d[b[j]]+1]+w[b[j]];
				if(i>=nxt[j]-j)dp[i][j]=min(dp[i][j],dp[i-(nxt[j]-j)][nxt[j]]);
			}
			else dp[i][j]=dp[i][j+1];
		}
	}
	printf("%lld\n",dp[k][1]);
}
